/**
 * @param {number[]} nums
 * @return {number}
 */
function solve(nums) {
    const n = nums.length;
    if (n < 3) {
        return 0;
    }

    // Helper function to compare two states (Count, Cost).
    // Returns true if State1 is strictly better than State2.
    // Better means higher count, or same count but lower cost.
    const isBetter = (state1, state2) => {
        if (state1.count !== state2.count) {
            return state1.count > state2.count;
        }
        // Counts are equal, prefer lower cost
        return state1.cost < state2.cost;
    };

    // 1. Calculate potential cost P[i] for each peak candidate i (1 <= i <= n-2)
    // P[i] is the minimum cost to make index i a peak, assuming neighbors stay at original values.
    const M = n - 2;
    const P = new Array(M + 1); // P[i] corresponds to index i+1 in the original array (1-based index for peaks)

    for (let i = 1; i <= M; i++) {
        // Peak candidate is nums[i]
        // Required value R >= max(nums[i-1] + 1, nums[i+1] + 1)
        const required_neighbor_max = Math.max(nums[i - 1] + 1, nums[i + 1] + 1);

        // Cost = max(0, Required - Current)
        const cost = Math.max(0, required_neighbor_max - nums[i]);
        P[i] = cost;
    }

    // 2. Dynamic Programming
    // DP[i] stores the best state (Count, Cost) achievable using peak indices up to i.
    // We use 1-based indexing for DP to align with peak indices 1 to M.
    // DP size M + 1.

    // State structure: { count: number, cost: number }
    const DP = new Array(M + 1);

    // Base case: DP[0] = state before considering any peaks (index 0).
    DP[0] = { count: 0, cost: 0 };

    // DP[1]: Considering only peak index 1.
    const R_take_1 = { count: 1, cost: P[1] };
    const R_skip_1 = { count: 0, cost: 0 };
    DP[1] = isBetter(R_take_1, R_skip_1) ? R_take_1 : R_skip_1;


    for (let i = 2; i <= M; i++) {
        // Option 1: Skip index i. Result inherited from DP[i-1].
        const R_skip = DP[i - 1];

        // Option 2: Take index i. Must skip i-1. Result comes from DP[i-2] + contribution of i.
        const R_take = {
            count: DP[i - 2].count + 1,
            cost: DP[i - 2].cost + P[i]
        };

        // Choose the best state
        if (isBetter(R_skip, R_take)) {
            DP[i] = R_skip;
        } else {
            DP[i] = R_take;
        }
    }

    // The final answer is the minimum cost associated with the best state found across all M potential peaks.
    return DP[M].cost;
}

